parameters.jsCode:
const text = $input.first().json.text;

// Extract fields using regex
const topic = text.match(/Topic:\s*(.*)/i)?.[1] || "";
const hook = text.match(/Hook:\s*(.*)/i)?.[1] || "";
const content = text.match(/Content:\s*([\s\S]*?)Hashtags:/i)?.[1]?.trim() || "";
const hashtags = text.match(/Hashtags:\s*(.*)/i)?.[1] || "";

return [{
  json: {
    Topic: topic,
    Hook: hook,
    Content: content,
    Hashtags: hashtags
  }
}];
